package com.example.login;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

import java.util.UUID;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (SessionManager.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);

        String savedEmail = SessionManager.getEmail(this);
        if (!TextUtils.isEmpty(savedEmail)) {
            emailInput.setText(savedEmail);
        }

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        String email = emailInput.getText() != null ? emailInput.getText().toString().trim() : "";
        String password = passwordInput.getText() != null ? passwordInput.getText().toString() : "";

        if (TextUtils.isEmpty(email)) {
            emailInput.setError("Email required");
            return;
        }
        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Password required");
            return;
        }

        setLoading(true);

        FakeAuthApi.login(email, password, new FakeAuthApi.Callback() {
            @Override
            public void onSuccess(String authToken) {
                runOnUiThread(() -> {
                    setLoading(false);
                    SessionManager.saveSession(LoginActivity.this, email, authToken);
                    startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                    finish();
                });
            }

            @Override
            public void onError(String message) {
                runOnUiThread(() -> {
                    setLoading(false);
                    Toast.makeText(LoginActivity.this, message, Toast.LENGTH_SHORT).show();
                });
            }
        });
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }
}

class SessionManager {
    private static final String PREFS_NAME = "demo_auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "auth_token";

    static void saveSession(Context context, String email, String token) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        sp.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    static boolean isLoggedIn(Context context) {
        return !TextUtils.isEmpty(getToken(context));
    }

    static String getEmail(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        return sp.getString(KEY_EMAIL, "");
    }

    static String getToken(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        return sp.getString(KEY_TOKEN, "");
    }

    static void clearSession(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        sp.edit().clear().apply();
    }
}

class FakeAuthApi {

    interface Callback {
        void onSuccess(String authToken);
        void onError(String message);
    }

    static void login(String email, String password, Callback callback) {
        new Thread(() -> {
            try {
                Thread.sleep(800);
            } catch (InterruptedException ignored) {
            }

            if (password.length() < 4) {
                callback.onError("Invalid credentials");
                return;
            }

            String token = "demo_" + UUID.randomUUID().toString();
            callback.onSuccess(token);
        }).start();
    }
}

package com.example.login;

import android.content.Intent;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView emailView;
    private TextView tokenView;
    private Button logoutButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!SessionManager.isLoggedIn(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        emailView = findViewById(R.id.emailView);
        tokenView = findViewById(R.id.tokenView);
        logoutButton = findViewById(R.id.logoutButton);

        emailView.setText(SessionManager.getEmail(this));
        tokenView.setText(SessionManager.getToken(this));

        logoutButton.setOnClickListener(v -> {
            SessionManager.clearSession(this);
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
    }
}

